import React, { useEffect, useState } from "react";
import {
  Box, Card, CardContent, Typography, Button, Snackbar, Alert
} from "@mui/material";
import { MapContainer, TileLayer, Marker, Polyline, Popup } from "react-leaflet";
import L from "leaflet";
import axios from "axios";
import { useAuth } from "../../contexts/AuthContext";
import { io } from "socket.io-client";

const socket = io("http://localhost:5000");

export default function RiderDashboard() {
  const [pendingRides, setPendingRides] = useState([]);
  const [selectedRide, setSelectedRide] = useState(null);
  const [route, setRoute] = useState(null);
  const [snackbar, setSnackbar] = useState({ open: false, message: "", type: "success" });

  const { auth } = useAuth();

  const pickupIcon = new L.Icon({
    iconUrl: "https://cdn-icons-png.flaticon.com/512/32/32339.png",
    iconSize: [25, 25],
  });
  const dropIcon = new L.Icon({
    iconUrl: "https://cdn-icons-png.flaticon.com/512/684/684908.png",
    iconSize: [35, 35],
  });

  // ✅ Fetch pending rides
  const fetchPendingRides = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/rides/pending", {
        headers: { Authorization: `Bearer ${auth?.token}` },
      });
      setPendingRides(res.data.rides || []);
    } catch {
      setSnackbar({ open: true, message: "Failed to fetch rides", type: "error" });
    }
  };

  // ✅ Accept ride
  const acceptRide = async (id) => {
    try {
      await axios.post(`http://localhost:5000/api/rides/${id}/accept`, {}, {
        headers: { Authorization: `Bearer ${auth?.token}` },
      });
      setSnackbar({ open: true, message: "Ride accepted!", type: "success" });
      fetchPendingRides();
    } catch {
      setSnackbar({ open: true, message: "Failed to accept ride", type: "error" });
    }
  };

  // ✅ Reject ride
  const rejectRide = async (id) => {
    try {
      await axios.post(`http://localhost:5000/api/rides/${id}/reject`, {}, {
        headers: { Authorization: `Bearer ${auth?.token}` },
      });
      fetchPendingRides();
    } catch {
      setSnackbar({ open: true, message: "Failed to reject ride", type: "error" });
    }
  };

  // ✅ Fetch route when ride is selected
  useEffect(() => {
    const fetchRoute = async () => {
      if (selectedRide?.pickupCoords && selectedRide?.dropCoords) {
        try {
          const res = await axios.get(
            `https://router.project-osrm.org/route/v1/driving/${selectedRide.pickupCoords.lng},${selectedRide.pickupCoords.lat};${selectedRide.dropCoords.lng},${selectedRide.dropCoords.lat}?overview=full&geometries=geojson`
          );
          const data = res.data.routes[0];
          setRoute(data.geometry.coordinates.map((c) => [c[1], c[0]]));
        } catch (err) {
          console.error("Route fetch failed:", err);
        }
      }
    };
    fetchRoute();
  }, [selectedRide]);

  // ✅ Listen for live ride requests via socket
  useEffect(() => {
    socket.on("rideRequest", (ride) => {
      setPendingRides((prev) => [ride, ...prev]);
    });
    return () => socket.off("rideRequest");
  }, []);

  return (
    <Box p={2} sx={{ display: "grid", gridTemplateColumns: "1fr 2fr", gap: 2 }}>
      {/* Left panel */}
      <Box>
        <Typography variant="h5" gutterBottom>Pending Ride Requests</Typography>
        {pendingRides.length === 0 ? (
          <Typography>No rides</Typography>
        ) : (
          pendingRides.map((ride) => (
            <Card key={ride._id} sx={{ mb: 2 }}>
              <CardContent>
                <Typography><b>Pickup:</b> {ride.pickup}</Typography>
                <Typography><b>Drop:</b> {ride.drop}</Typography>
                <Typography>Status: {ride.status}</Typography>
                <Box mt={2} display="flex" gap={2}>
                  <Button variant="contained" color="success" onClick={() => acceptRide(ride._id)}>Accept</Button>
                  <Button variant="contained" color="error" onClick={() => rejectRide(ride._id)}>Reject</Button>
                  <Button variant="outlined" onClick={() => setSelectedRide(ride)}>View on Map</Button>
                </Box>
              </CardContent>
            </Card>
          ))
        )}
      </Box>

      {/* Right panel (map) */}
      <Box>
        <MapContainer center={[17.385, 78.4867]} zoom={12} style={{ height: "600px", width: "100%" }}>
          <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
          {selectedRide?.pickupCoords && (
            <Marker position={selectedRide.pickupCoords} icon={pickupIcon}><Popup>Pickup</Popup></Marker>
          )}
          {selectedRide?.dropCoords && (
            <Marker position={selectedRide.dropCoords} icon={dropIcon}><Popup>Drop</Popup></Marker>
          )}
          {route && <Polyline positions={route} pathOptions={{ color: "black", weight: 4 }} />}
        </MapContainer>
      </Box>

      <Snackbar open={snackbar.open} autoHideDuration={3000} onClose={() => setSnackbar({ ...snackbar, open: false })}>
        <Alert severity={snackbar.type}>{snackbar.message}</Alert>
      </Snackbar>
    </Box>
  );
}
